class QueueWithStacks {
  Deque<Integer> in = new ArrayDeque<>(), out = new ArrayDeque<>();
  void enqueue(int x){ in.push(x); }
  int dequeue(){
    if(out.isEmpty()) while(!in.isEmpty()) out.push(in.pop());
    return out.pop();
  }
}

class MinStack {
  Deque<Integer> stack = new ArrayDeque<>(), minStack = new ArrayDeque<>();
  void push(int x){
    stack.push(x);
    minStack.push(minStack.isEmpty() ? x : Math.min(x, minStack.peek()));
  }
  void pop(){ stack.pop(); minStack.pop(); }
  int getMin(){ return minStack.peek(); }
}

boolean isValidBST(Node node, Integer min, Integer max){
  if(node == null) return true;
  if((min != null && node.val <= min) || (max != null && node.val >= max)) return false;
  return isValidBST(node.left, min, node.val) && isValidBST(node.right, node.val, max);
}

